body {
  margin: 0;
  padding: 0;
  font-size: 14px;
  font-family: Arial, Helvetica, sans-serif;
}

a {
  text-decoration: none;
  cursor: pointer;
}

.header {
  width: 100%;
  height: 60px;
}

header nav {
  display: flex;
  justify-content: right;
}

header nav .nav-right-section {
  width: 250px;
  height: auto;
  display: flex;
  list-style: none;
  justify-content: center;
  align-items: center;
}

nav .nav-right-section li {
  margin-right: 10px;
  color: black;
}

nav .nav-right-section img {
  border-radius: 50px;
  margin-left: 10px;
}

main {
  margin-top: 150px;
  text-align: center;
}

main .main-logo {
  width: 530px;
  margin: 0 auto;
  margin-bottom: 35px;
}

main .main-logo img {
  width: 272px;
  height: 92px;
}

main .main-input {
  width: 530px;
  margin: 0 auto;
  margin-bottom: 35px;
}

main .main-input-container {
  width: 525px;
  border-radius: 100px;
  border: 1px solid #dfe1e5;
  display: flex;
  justify-content: center;
  align-items: center;
}

main .main-input input {
  width: 450px;
  height: 40px;
  border: none;
  outline: none;
}

main .main-input-container:hover {
  box-shadow: 0 1px 6px 0 #20212447;
  border-color: #dfe1e500;
}

main .main-input .search-icon {
  background-image: url('https://img.icons8.com/android/24/000000/search.png');
  background-repeat: no-repeat;
  background-position: center;
  background-size: contain;
  width: 18px;
  height: 18px;
}

main .main-input .micro-icon {
  background-image: url('https://www.gstatic.com/images/branding/googlemic/2x/googlemic_color_24dp.png');
  background-repeat: no-repeat;
  background-position: center;
  background-size: contain;
  width: 18px;
  height: 18px;
  cursor: pointer;
}

main .main-buttons {
  width: 530px;
  margin: 0 auto;
}

main .main-buttons div {
  display: inline-block;
}

main .main-buttons button {
  height: 36px;
  background-color: #f2f2f2;
  border: 1px solid #f2f2f2;
  font-size: 14px;
  color: #5f6368;
  border-radius: 5px;
  padding: 0 15px;
  margin-right: 15px;
  cursor: pointer;
}

main .main-buttons button:hover {
  border: 1px solid #c6c6c6c6;
  box-shadow: 0 1px 1px rgba(0, 0, 0, 0.1);
  color: #222;
  background-color: #f8f8f8;
}

footer {
  width: 100%;
  height: 50px;
  position: absolute;
  bottom: 0;
  display: grid;
  grid-template-columns: 1fr 1fr;
  align-items: center;
  font-size: 13px;
  background-color: #f2f2f2;
  border-top: 1px solid #e4e4e4;
}

footer ul {
  margin: 10px;
  list-style: none;
  display: flex;
  padding-left: 0;
}

footer ul li a {
  margin: 10px;
  color: #5f6368;
}

footer .footer-left {
  justify-self: left;
}

footer .footer-right {
  justify-self: right;
}

body {
  font-family: Arial, sans-serif;
  background-color: #f2f2f2;
  margin: 0;
  padding: 0;
}

.container {
  max-width: 600px;
  height: 100%;
  margin: 0 auto;
  padding: 20px;
  text-align: center;
}

.intro {
  padding: auto;
  margin: auto;
  weight: 100%;
  display: flex;
  flex-direction: col;
  justify-content: center;
  items-align: center;
}

.intro img {
  border-radius: 300px;
  margin: auto;
  height: 150px;
  width: 150px;
}

.nickname {
  font-size: 16px;
  font-weight: normal;
}

hr {
  background-color: black;
}

.social-networks {
  display: flex;
  justify-content: center;
}

.social-networks svg {
  height: 30px;
  width: 30px;
  margin: 5px 5px;
}

.link {
  display: flex;
  flex-direction: row;
  background-color: #fff;
  border-radius: 10px;
  padding: 5px 20px;
  margin: 10px 0px;
  text-decoration: none;
  color: #333;
  justify-content: space-between;
  align-items: center;
}

.link img {
  width: 80px;
  height: 40px;
  border-radius: 5px;
}

.link h2 {
  font-size: 16px;
  font-weight: bold;
  margin-bottom: 20px;
}

.link i {
  font-size: 25px;
}

.footer {
  text-align: center;
}
